                }
            }
            if (!valid) continue;

            // Check nums[q..n-1] is strictly increasing
            for (int i = q + 1; i < n; ++i) {
                if (nums[i] <= nums[i-1]) {
                    valid = false;
                    break;
                }
            }
            if (valid) return true;
        }
    }
